import re
from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json

app = Flask(__name__)

# Configuration
KAFKA_BOOTSTRAP_SERVERS = ['localhost:9092']

# Allowlist of topics that clients are permitted to publish to.
# This prevents unauthorized access to internal/sensitive topics.
ALLOWED_TOPICS = frozenset([
    'user-events',
    'page-views',
    'click-events',
    'notifications',
    'audit-log',
])

# Regex pattern for valid topic names (alphanumeric, hyphens, underscores)
VALID_TOPIC_PATTERN = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9._-]{0,248}$')

producer = KafkaProducer(
    bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
    value_serializer=lambda v: json.dumps(v).encode('utf-8'),
    key_serializer=lambda v: v.encode('utf-8') if v else None,
    acks='all',
    retries=3,
    max_request_size=1048576,  # 1MB max message size
)


def validate_topic(topic_name):
    """Validate and authorize the requested topic name."""
    if not topic_name or not isinstance(topic_name, str):
        return False, "Topic name is required and must be a string."

    topic_name = topic_name.strip()

    # Validate topic name format to prevent injection
    if not VALID_TOPIC_PATTERN.match(topic_name):
        return False, "Topic name contains invalid characters."

    # Check against allowlist — this is the critical security control
    # that prevents publishing to arbitrary/internal topics
    if topic_name not in ALLOWED_TOPICS:
        return False, f"Topic '{topic_name}' is not in the list of permitted topics."

    return True, topic_name


def validate_message(message):
    """Validate the message payload."""
    if message is None:
        return False, "Message payload is required."

    serialized = json.dumps(message)
    if len(serialized.encode('utf-8')) > 1048576:
        return False, "Message payload exceeds maximum size of 1MB."

    return True, message


@app.route('/publish', methods=['POST'])
def publish_message():
    """Publish a message to a Kafka topic specified by the user.

    The topic must be in the configured allowlist. Arbitrary topic names
    are rejected to prevent unauthorized access to internal topics such as
    __consumer_offsets or other sensitive streams.
    """
    content_type = request.content_type or ''
    if 'application/json' not in content_type:
        return jsonify({'error': 'Content-Type must be application/json'}), 415

    try:
        data = request.get_json(force=False, silent=False)
    except Exception:
        return jsonify({'error': 'Invalid JSON payload'}), 400

    if not data or not isinstance(data, dict):
        return jsonify({'error': 'Request body must be a JSON object'}), 400

    topic_name = data.get('topic')
    message = data.get('message')
    key = data.get('key')

    # Validate and authorize the topic
    is_valid, result = validate_topic(topic_name)
    if not is_valid:
        return jsonify({'error': result}), 400

    topic_name = result

    # Validate the message
    is_valid, result = validate_message(message)
    if not is_valid:
        return jsonify({'error': result}), 400

    message = result

    # Validate optional key
    if key is not None:
        if not isinstance(key, str) or len(key) > 256:
            return jsonify({'error': 'Key must be a string of at most 256 characters'}), 400

    try:
        future = producer.send(topic_name, value=message, key=key)
        record_metadata = future.get(timeout=10)

        return jsonify({
            'status': 'success',
            'topic': record_metadata.topic,
            'partition': record_metadata.partition,
            'offset': record_metadata.offset,
        }), 200

    except Exception as e:
        # Log the full error server-side but don't leak internals to the client
        app.logger.error(f"Failed to publish to topic '{topic_name}': {e}")
        return jsonify({'error': 'Failed to publish message. Please try again later.'}), 500


@app.route('/topics', methods=['GET'])
def list_allowed_topics():
    """Return the list of topics that clients are allowed to publish to."""
    return jsonify({'allowed_topics': sorted(ALLOWED_TOPICS)}), 200


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200


if __name__ == '__main__':
    app.run(host='127.0.0.1', port=5000, debug=False)